import { useEffect, useRef } from "react";

export default function Particles() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    let animId;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener("resize", resize);

    const particles = Array.from({ length: 80 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.4,
      r: Math.random() * 1.5 + 0.5,
    }));

    function draw() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];
        p.x += p.vx;
        p.y += p.vy;
        if (p.x < 0 || p.x > canvas.width) p.vx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(212, 167, 84, 0.5)";
        ctx.fill();

        for (let j = i + 1; j < particles.length; j++) {
          const q = particles[j];
          const dist = Math.hypot(p.x - q.x, p.y - q.y);
          if (dist < 120) {
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(q.x, q.y);
            ctx.strokeStyle = `rgba(212, 167, 84, ${0.08 * (1 - dist / 120)})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }
      }
      animId = requestAnimationFrame(draw);
    }
    draw();

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener("resize", resize);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: "absolute",
        inset: 0,
        pointerEvents: "none",
      }}
    />
  );
}

import { useState, useEffect } from "react";
import styles from "./Header.module.css";

const navLinks = [
  { href: "#home", label: "首页" },
  { href: "#work", label: "作品" },
  { href: "#contact", label: "联系" },
];

export default function Header() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <header className={`${styles.header} ${scrolled ? styles.scrolled : ""}`}>
      <div className={styles.inner}>
        <a href="#home" className={styles.logo}>
          <span className={styles.brand}>APOGEE</span>
          <span className={styles.sub}>创科文化传媒</span>
        </a>

        <nav className={`${styles.nav} ${menuOpen ? styles.open : ""}`}>
          {navLinks.map((link) => (
            <a
              key={link.href}
              href={link.href}
              className={styles.link}
              onClick={() => setMenuOpen(false)}
            >
              {link.label}
            </a>
          ))}
        </nav>

        <button
          className={styles.hamburger}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="菜单"
        >
          <span className={menuOpen ? styles.barOpen : styles.bar} />
          <span className={menuOpen ? styles.barOpen : styles.bar} />
          <span className={menuOpen ? styles.barOpen : styles.bar} />
        </button>
      </div>
    </header>
  );
}

.header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  height: var(--nav-height);
  transition: background 0.3s, backdrop-filter 0.3s;
}

.scrolled {
  background: rgba(10, 10, 14, 0.8);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
}

.inner {
  max-width: var(--max-width);
  margin: 0 auto;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 24px;
}

.logo {
  display: flex;
  align-items: baseline;
  gap: 8px;
  text-decoration: none;
}

.brand {
  font-size: 1.25rem;
  font-weight: 800;
  letter-spacing: 2px;
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.sub {
  font-size: 0.75rem;
  color: var(--text-secondary);
  letter-spacing: 1px;
}

.nav {
  display: flex;
  gap: 32px;
}

.link {
  color: var(--text-secondary);
  font-size: 0.9rem;
  letter-spacing: 1px;
  transition: color 0.2s;
}

.link:hover {
  color: var(--accent-light);
}

.hamburger {
  display: none;
  flex-direction: column;
  gap: 5px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 4px;
}

.bar,
.barOpen {
  display: block;
  width: 22px;
  height: 2px;
  background: var(--text-primary);
  border-radius: 1px;
  transition: transform 0.3s, opacity 0.3s;
}

@media (max-width: 768px) {
  .hamburger {
    display: flex;
    z-index: 101;
  }

  .nav {
    position: fixed;
    inset: 0;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 40px;
    background: rgba(10, 10, 14, 0.96);
    backdrop-filter: blur(16px);
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s;
  }

  .nav.open {
    opacity: 1;
    pointer-events: auto;
  }

  .link {
    font-size: 1.25rem;
  }
}

.hero {
  position: relative;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 24px;
  overflow: hidden;
}

.content {
  position: relative;
  z-index: 1;
  max-width: 720px;
}

.tagline {
  font-size: 0.9rem;
  letter-spacing: 4px;
  color: var(--accent);
  text-transform: uppercase;
  margin-bottom: 24px;
  opacity: 0;
  animation: fadeUp 0.8s ease forwards;
  animation-delay: 0.2s;
}

.title {
  margin-bottom: 24px;
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  justify-content: center;
  gap: 12px;
  opacity: 0;
  animation: fadeUp 0.8s ease forwards;
  animation-delay: 0.5s;
}

.brand {
  font-size: clamp(2.5rem, 6vw, 4.5rem);
  font-weight: 900;
  letter-spacing: 6px;
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.divider {
  color: var(--text-muted);
  font-weight: 300;
  font-size: clamp(1.5rem, 4vw, 3rem);
}

.sub {
  font-size: clamp(1.2rem, 3vw, 2rem);
  font-weight: 300;
  color: var(--text-secondary);
  letter-spacing: 4px;
}

.desc {
  font-size: 1.05rem;
  color: var(--text-secondary);
  line-height: 1.8;
  margin-bottom: 40px;
  opacity: 0;
  animation: fadeUp 0.8s ease forwards;
  animation-delay: 0.8s;
}

.cta {
  display: inline-block;
  padding: 14px 48px;
  border: 1px solid var(--accent);
  color: var(--accent);
  font-size: 0.95rem;
  letter-spacing: 2px;
  border-radius: 4px;
  transition: background 0.3s, color 0.3s, box-shadow 0.3s;
  opacity: 0;
  animation: fadeUp 0.8s ease forwards;
  animation-delay: 1.1s;
}

.cta:hover {
  background: var(--accent);
  color: var(--bg-deep);
  box-shadow: 0 0 24px var(--border-glow);
}

.scroll {
  position: absolute;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%);
  opacity: 0;
  animation: fadeUp 0.8s ease forwards;
  animation-delay: 1.4s;
}

.scrollIcon {
  display: block;
  width: 20px;
  height: 32px;
  border: 2px solid var(--text-muted);
  border-radius: 10px;
  position: relative;
}

.scrollIcon::after {
  content: "";
  position: absolute;
  top: 6px;
  left: 50%;
  transform: translateX(-50%);
  width: 4px;
  height: 8px;
  background: var(--accent);
  border-radius: 2px;
  animation: scrollWheel 2s ease infinite;
}

@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes scrollWheel {
  0%,
  100% {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
  50% {
    opacity: 0.3;
    transform: translateX(-50%) translateY(8px);
  }
}

import { useState } from "react";
import videos, { categories } from "../data/videos";
import styles from "./VideoGallery.module.css";

export default function VideoGallery() {
  const [active, setActive] = useState("全部");
  const [activeVideo, setActiveVideo] = useState(null);

  const filtered =
    active === "全部" ? videos : videos.filter((v) => v.category === active);

  return (
    <section id="work">
      <h2 className="section-title">精选作品</h2>

      <div className={styles.filters}>
        {categories.map((cat) => (
          <button
            key={cat}
            className={`${styles.filterBtn} ${active === cat ? styles.active : ""}`}
            onClick={() => setActive(cat)}
          >
            {cat}
          </button>
        ))}
      </div>

      <div className={styles.grid}>
        {filtered.map((video) => (
          <div
            key={video.title}
            className={styles.card}
            onClick={() => setActiveVideo(video)}
          >
            <div className={styles.thumb}>
              <iframe
                src={`https://www.youtube.com/embed/${video.id}?controls=0&modestbranding=1&showinfo=0`}
                title={video.title}
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                allowFullScreen
                className={styles.iframe}
              />
              <div className={styles.playOverlay}>
                <span className={styles.playIcon}>▶</span>
              </div>
            </div>
            <div className={styles.info}>
              <h3 className={styles.videoTitle}>{video.title}</h3>
              <span className={styles.category}>{video.category}</span>
            </div>
          </div>
        ))}
      </div>

      {activeVideo && (
        <div className={styles.modal} onClick={() => setActiveVideo(null)}>
          <div className={styles.modalInner} onClick={(e) => e.stopPropagation()}>
            <button
              className={styles.close}
              onClick={() => setActiveVideo(null)}
            >
              ×
            </button>
            <div className={styles.modalFrame}>
              <iframe
                src={`https://www.youtube.com/embed/${activeVideo.id}?autoplay=1&modestbranding=1&rel=0`}
                title={activeVideo.title}
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                allowFullScreen
                className={styles.modalIframe}
              />
            </div>
            <h3 className={styles.modalTitle}>{activeVideo.title}</h3>
          </div>
        </div>
      )}
    </section>
  );
}

.filters {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 12px;
  margin-bottom: 40px;
}

.filterBtn {
  padding: 8px 20px;
  border: 1px solid var(--border);
  border-radius: 24px;
  background: transparent;
  color: var(--text-secondary);
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.25s;
  letter-spacing: 1px;
}

.filterBtn:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.filterBtn.active {
  background: var(--accent-gradient);
  color: var(--bg-deep);
  border-color: transparent;
  font-weight: 600;
}

.grid {
  max-width: var(--max-width);
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
  gap: 24px;
}

.card {
  background: var(--bg-card);
  border-radius: var(--radius);
  border: 1px solid var(--border);
  overflow: hidden;
  cursor: pointer;
  transition: transform 0.3s, border-color 0.3s, box-shadow 0.3s;
}

.card:hover {
  transform: translateY(-4px);
  border-color: var(--border-glow);
  box-shadow: 0 8px 32px rgba(212, 167, 84, 0.1);
}

.thumb {
  position: relative;
  aspect-ratio: 16 / 9;
  background: #000;
}

.iframe {
  width: 100%;
  height: 100%;
  border: none;
  pointer-events: none;
}

.playOverlay {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.3);
  opacity: 0;
  transition: opacity 0.3s;
}

.card:hover .playOverlay {
  opacity: 1;
}

.playIcon {
  font-size: 2.5rem;
  color: var(--accent);
  text-shadow: 0 0 16px var(--border-glow);
}

.info {
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.videoTitle {
  font-size: 0.95rem;
  font-weight: 600;
  color: var(--text-primary);
}

.category {
  font-size: 0.8rem;
  color: var(--accent);
  padding: 4px 10px;
  border: 1px solid rgba(212, 167, 84, 0.3);
  border-radius: 12px;
  letter-spacing: 1px;
}

/* Modal */
.modal {
  position: fixed;
  inset: 0;
  z-index: 200;
  background: rgba(0, 0, 0, 0.88);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  animation: fadeIn 0.3s ease;
}

.modalInner {
  width: 100%;
  max-width: 900px;
}

.modalFrame {
  position: relative;
  padding-top: 56.25%;
}

.modalIframe {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  border: none;
  border-radius: var(--radius);
}

.modalTitle {
  margin-top: 16px;
  font-size: 1.1rem;
  text-align: center;
  color: var(--text-primary);
}

.close {
  display: block;
  margin-left: auto;
  margin-bottom: 12px;
  background: none;
  border: none;
  color: var(--text-secondary);
  font-size: 2rem;
  cursor: pointer;
  transition: color 0.2s;
  line-height: 1;
}

.close:hover {
  color: var(--accent);
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@media (max-width: 768px) {
  .grid {
    grid-template-columns: 1fr;
  }
}

